package com.example.biometriclogin;

import android.content.Context;
import android.content.SharedPreferences;

public final class Prefs {
    private static final String FILE = "auth_prefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_LOGGED_IN = "logged_in";

    private static SharedPreferences sp;

    private Prefs() {}

    public static void init(Context context) {
        if (sp == null) {
            sp = context.getApplicationContext().getSharedPreferences(FILE, Context.MODE_PRIVATE);
        }
    }

    private static SharedPreferences sp(Context context) {
        if (sp == null) init(context);
        return sp;
    }

    public static boolean isBiometricEnabled(Context context) {
        return sp(context).getBoolean(KEY_BIOMETRIC_ENABLED, false);
    }

    public static void setBiometricEnabled(Context context, boolean enabled) {
        sp(context).edit().putBoolean(KEY_BIOMETRIC_ENABLED, enabled).apply();
    }

    public static boolean isLoggedIn(Context context) {
        return sp(context).getBoolean(KEY_LOGGED_IN, false);
    }

    public static void setLoggedIn(Context context, boolean loggedIn) {
        sp(context).edit().putBoolean(KEY_LOGGED_IN, loggedIn).apply();
    }

    public static void logout(Context context) {
        sp(context).edit().putBoolean(KEY_LOGGED_IN, false).apply();
    }
}

package com.example.biometriclogin;

import android.content.Context;

import androidx.biometric.BiometricManager;

public final class BiometricUtils {
    private BiometricUtils() {}

    public static boolean canAuthenticateStrongOrDeviceCredential(Context context) {
        BiometricManager bm = BiometricManager.from(context);
        int res = bm.canAuthenticate(
                BiometricManager.Authenticators.BIOMETRIC_STRONG
                        | BiometricManager.Authenticators.DEVICE_CREDENTIAL
        );
        return res == BiometricManager.BIOMETRIC_SUCCESS;
    }
}

