package com.example.biometriclogin;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText etUsername;
    private EditText etPassword;
    private CheckBox cbEnableBiometric;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (Prefs.isLoggedIn(this)) {
            openHome();
            return;
        }

        setContentView(R.layout.activity_login);

        etUsername = findViewById(R.id.etUsername);
        etPassword = findViewById(R.id.etPassword);
        cbEnableBiometric = findViewById(R.id.cbEnableBiometric);
        Button btnLogin = findViewById(R.id.btnLogin);

        cbEnableBiometric.setChecked(Prefs.isBiometricEnabled(this));

        btnLogin.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                attemptLogin();
            }
        });

        Button btnUseBiometric = findViewById(R.id.btnUseBiometric);
        if (btnUseBiometric != null) {
            btnUseBiometric.setVisibility(Prefs.isBiometricEnabled(this) ? View.VISIBLE : View.GONE);
            btnUseBiometric.setOnClickListener(new View.OnClickListener() {
                @Override
                public void onClick(View v) {
                    startActivity(new Intent(LoginActivity.this, BiometricUnlockActivity.class));
                }
            });
        }
    }

    private void attemptLogin() {
        String u = etUsername.getText() != null ? etUsername.getText().toString() : "";
        String p = etPassword.getText() != null ? etPassword.getText().toString() : "";

        if (TextUtils.isEmpty(u) || TextUtils.isEmpty(p)) {
            Toast.makeText(this, "Enter username and password", Toast.LENGTH_SHORT).show();
            return;
        }

        Prefs.setLoggedIn(this, true);

        boolean enable = cbEnableBiometric.isChecked();
        if (enable) {
            if (!BiometricUtils.canAuthenticateStrongOrDeviceCredential(this)) {
                Toast.makeText(this, "Biometric not available. Keeping password login.", Toast.LENGTH_SHORT).show();
                Prefs.setBiometricEnabled(this, false);
            } else {
                Prefs.setBiometricEnabled(this, true);
            }
        } else {
            Prefs.setBiometricEnabled(this, false);
        }

        openHome();
    }

    private void openHome() {
        Intent i = new Intent(this, HomeActivity.class);
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(i);
        finish();
    }
}

package com.example.biometriclogin;

import android.content.Intent;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;

import androidx.activity.OnBackPressedCallback;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class BiometricUnlockActivity extends AppCompatActivity {

    private BiometricPrompt biometricPrompt;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (!Prefs.isBiometricEnabled(this)) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        getOnBackPressedDispatcher().addCallback(this, new OnBackPressedCallback(true) {
            @Override
            public void handleOnBackPressed() {
                finish();
            }
        });

        setContentView(R.layout.activity_biometric_unlock);

        Executor executor = ContextCompat.getMainExecutor(this);
        biometricPrompt = new BiometricPrompt(this, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                Prefs.setLoggedIn(BiometricUnlockActivity.this, true);
                Intent i = new Intent(BiometricUnlockActivity.this, HomeActivity.class);
                i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
                startActivity(i);
                finish();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                new Handler(Looper.getMainLooper()).postDelayed(new Runnable() {
                    @Override
                    public void run() {
                        finish();
                    }
                }, 200);
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
            }
        });

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Unlock with biometrics")
                .setSubtitle("Use your fingerprint to unlock")
                .setAllowedAuthenticators(
                        androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG
                                | androidx.biometric.BiometricManager.Authenticators.DEVICE_CREDENTIAL
                )
                .build();

        biometricPrompt.authenticate(promptInfo);
    }
}

package com.example.biometriclogin;

import android.content.Intent;
import android.os.Bundle;

import androidx.appcompat.app.AppCompatActivity;

public class SplashActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (Prefs.isBiometricEnabled(this)) {
            startActivity(new Intent(this, BiometricUnlockActivity.class));
        } else if (Prefs.isLoggedIn(this)) {
            startActivity(new Intent(this, HomeActivity.class));
        } else {
            startActivity(new Intent(this, LoginActivity.class));
        }
        finish();
    }
}